const input = $('Workflow Input').item.json;
const orders = $input.all();

if (!orders || orders.length === 0) {
  return [{
    json: {
      success: false,
      eligible: false,
      error: 'order_not_found',
      message: `Nie znaleziono zamówienia o numerze ${input.order_number}. Proszę sprawdzić numer zamówienia.`
    }
  }];
}

const order = orders[0].json;

// Check if order status allows returns
const returnableStatuses = ['shipped', 'delivered'];
if (!returnableStatuses.includes(order.status)) {
  let message = '';
  if (order.status === 'new' || order.status === 'processing') {
    message = 'Zamówienie nie zostało jeszcze wysłane. Jeśli chcesz je anulować, skontaktuj się z nami bezpośrednio.';
  } else if (order.status === 'returned') {
    message = 'To zamówienie zostało już zwrócone.';
  } else {
    message = `Zamówienie w statusie "${order.status}" nie kwalifikuje się do zwrotu online.`;
  }

  return [{
    json: {
      success: false,
      eligible: false,
      error: 'invalid_status',
      order_status: order.status,
      message: message
    }
  }];
}

// Check 14-day return window
const orderDate = new Date(order.created_at);
const now = new Date();
const daysDiff = Math.floor((now - orderDate) / (1000 * 60 * 60 * 24));

if (daysDiff > 14) {
  return [{
    json: {
      success: false,
      eligible: false,
      error: 'return_period_expired',
      days_since_order: daysDiff,
      message: `Niestety, upłynął 14-dniowy termin na zwrot (zamówienie złożone ${daysDiff} dni temu). Jeśli uważasz, że jest to błąd lub masz szczególne okoliczności, skontaktuj się z nami bezpośrednio.`
    }
  }];
}

// Check for existing return
return [{
  json: {
    success: true,
    eligible: true,
    order_id: order.id,
    order_number: order.order_number,
    reason: input.reason,
    items: input.items || [],
    days_remaining: 14 - daysDiff
  }
}];

const validation = $('Validate Return').item.json;
const returnResult = $input.all();

if (!returnResult || returnResult.length === 0) {
  return [{
    json: {
      success: false,
      message: 'Wystąpił błąd podczas tworzenia zgłoszenia zwrotu. Proszę spróbować ponownie lub skontaktować się z obsługą klienta.'
    }
  }];
}

const returnId = returnResult[0].json.id;

return [{
  json: {
    success: true,
    return_id: returnId,
    order_number: validation.order_number,
    reason: validation.reason,
    status: 'created',
    instructions: `Zgłoszenie zwrotu ${returnId} zostało utworzone pomyślnie.\n\nInstrukcje:\n1. Zapakuj produkt w oryginalne opakowanie (jeśli możliwe)\n2. Dołącz do paczki numer zwrotu: ${returnId}\n3. Wyślij paczkę na adres:\n   Magazyn Demo Sklep\n   ul. Magazynowa 10\n   00-001 Warszawa\n\nZwrot środków nastąpi w ciągu 7 dni roboczych od otrzymania przesyłki.`,
    refund_info: 'Zwrot środków na konto w ciągu 7 dni roboczych od otrzymania paczki w magazynie.',
    message: `Utworzono zgłoszenie zwrotu o numerze ${returnId}. Szczegółowe instrukcje zostały przygotowane.`
  }
}];
